#!/bin/bash
python benchmark_agent.py --input data/input/like_interrater.csv --model anthropic/claude-haiku-4-5 --repeat_unclassified --task_name "*like* discourse/pragm" --task_description "Classification of instance of *like* into four discourse-pragmatic categories: 1. Quotative marker, 2. Discourse marker, 3. Clause-medial pragmatic marker, 4. Clause-final pragmatic marker" --tags "*like*;discourse;pragmatics;English;v3" --calibration --provider requesty --system_prompt_b64  --enable_cot --threads 5 --strict_control_acceptance --requesty_auto_cache
python benchmark_agent.py --input data/input/adv-ing.csv --model anthropic/claude-haiku-4-5 --repeat_unclassified --task_name "ADV *-ing* clause" --tags '*-ing*; syntax; adverbial; clause; English' --task_description "Classification of adverbial *-ing* clauses as one of: FA (Free Adjunct), AVG (Adverbial Verbal Gerund) or AC (Absolute Construction)." --provider requesty --strict_control_acceptance --requesty_auto_cache --system_prompt_b64  --calibration --enable_cot --threads 5
python benchmark_agent.py --input data/input/OE_number.csv --provider requesty --model anthropic/claude-haiku-4-5 --requesty_auto_cache --repeat_unclassified --task_name 'OE number' --task_description 'Determining grammatical number (sg./pl.) in Old English nouns.' --tags 'Old English;morphology;number' --calibration --system_prompt_b64  --enable_cot --threads 5
python benchmark_agent.py --input data/input/ycoe3.csv --provider requesty --model anthropic/claude-haiku-4-5 --requesty_auto_cache --task_name 'OE lemmatization' --tags 'Old English; lemmatization; morphology; v3' --task_description 'Old English lemmatization of an excerpt from the YCOE corpus.' --threads 5 --request_timeout_seconds 300 --strict_control_acceptance --system_prompt_b64  --enable_cot --calibration